// src/components/CouponForm/index.jsx (Используется на MainPage)

import React from 'react';
import { useForm } from 'react-hook-form';
import { BASE_URL } from '../../utils/api';
import s from './CouponForm.module.css';
import Button from '../UI/Button';

const CouponForm = () => {
  const { 
    register, 
    handleSubmit, 
    formState: { errors },
    reset 
  } = useForm();

  const onSubmit = async (data) => {
    try {
      const response = await fetch(`${BASE_URL}/sale/send`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ phone: data.phone }),
      });

      if (response.ok) {
        alert('Спасибо! Ваш купон на скидку отправлен.');
        reset(); 
      } else {
        alert('Ошибка при отправке заявки.');
      }
    } catch (error) {
      console.error('Ошибка сети:', error);
      alert('Ошибка соединения с сервером.');
    }
  };

  return (
    <div className={s.container}>
      <h2>Получите скидку 10% на первый заказ!</h2>
      <form onSubmit={handleSubmit(onSubmit)} className={s.form}>

        <input
          type="tel"
          placeholder="Ваш номер телефона"
          className={s.input}
          {...register('phone', { 
            required: 'Введите номер телефона',
            pattern: {
                value: /^\+?[0-9\s-()]{7,20}$/,
                message: 'Некорректный формат телефона'
            }
          })}
        />
        <Button type="submit" className={s.submitButton}>
          Получить скидку
        </Button>
      </form>
      {errors.phone && <p className={s.error}>{errors.phone.message}</p>}
    </div>
  );
};

export default CouponForm;
